/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Lista de Cadastro de Salário Funcionário"
//Report Template Source Header &AppName = "DVelop Software Solutions" &Phone = !"+1 550 8923" &Mail = !"info@mail.com" &Website = !"http://www.web.com" &AddressLine1 = !"French Boulevard 2859" &AddressLine2 = !"Downtown" &AddressLine3 = !"Paris, France" Print printTitle End Footer &PageInfo = "Page: " + &Page.ToString().Trim() &DateInfo = "Date: " + &Today.ToFormattedString() Print printFooter End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &PesCod.IsEmpty() print printBlockFilterPesCod EndIf If not &IncluirDemitidos.IsEmpty() &FilterIncluirDemitidosValueDescription = '' Do Case Case &IncluirDemitidos.ToString().Trim() = !"S" &FilterIncluirDemitidosValueDescription = "Incluir Demitidos"
Case &IncluirDemitidos.ToString().Trim() = !"N" &FilterIncluirDemitidosValueDescription = " Funcionários Vigêntes"
EndCase
print printBlockFilterIncluirDemitidos EndIf If not &PesIsFun.IsEmpty() &FilterPesIsFunValueDescription = '' Do Case Case &PesIsFun.ToString().Trim() = !"true" &FilterPesIsFunValueDescription = "Somente Funcionários"
Case &PesIsFun.ToString().Trim() = !"false" &FilterPesIsFunValueDescription = "Todas as Pessoas"
EndCase
print printBlockFilterPesIsFun EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'PESRAZ' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &PesRaz1.FromString(&GridStateDynamicFilter.Value) If not &PesRaz1.IsEmpty() Do Case Case &DynamicFiltersOperator1 = 0 &FilterPesRazDescription = format('%1 (%2)', "Nome Funcionário", "Começa com") Case &DynamicFiltersOperator1 = 1 &FilterPesRazDescription = format('%1 (%2)', "Nome Funcionário", "Contém") EndCase &PesRaz = &PesRaz1 print printBlockFilterPesRaz EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'PESRAZ' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &PesRaz2.FromString(&GridStateDynamicFilter.Value) If not &PesRaz2.IsEmpty() Do Case Case &DynamicFiltersOperator2 = 0 &FilterPesRazDescription = format('%1 (%2)', "Nome Funcionário", "Começa com") Case &DynamicFiltersOperator2 = 1 &FilterPesRazDescription = format('%1 (%2)', "Nome Funcionário", "Contém") EndCase &PesRaz = &PesRaz2 print printBlockFilterPesRaz EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'PESRAZ' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &PesRaz3.FromString(&GridStateDynamicFilter.Value) If not &PesRaz3.IsEmpty() Do Case Case &DynamicFiltersOperator3 = 0 &FilterPesRazDescription = format('%1 (%2)', "Nome Funcionário", "Começa com") Case &DynamicFiltersOperator3 = 1 &FilterPesRazDescription = format('%1 (%2)', "Nome Funcionário", "Contém") EndCase &PesRaz = &PesRaz3 print printBlockFilterPesRaz EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod PesRaz when &OrderedBy = 1 order PesCod when &OrderedBy = 2 AND &OrderedDsc = False order (PesCod) when &OrderedBy = 2 AND &OrderedDsc = True order PesRaz when &OrderedBy = 3 AND &OrderedDsc = False order (PesRaz) when &OrderedBy = 3 AND &OrderedDsc = True order FucCodNom when &OrderedBy = 4 AND &OrderedDsc = False order (FucCodNom) when &OrderedBy = 4 AND &OrderedDsc = True order PesSetNom when &OrderedBy = 5 AND &OrderedDsc = False order (PesSetNom) when &OrderedBy = 5 AND &OrderedDsc = True order PesIsFun when &OrderedBy = 6 AND &OrderedDsc = False order (PesIsFun) when &OrderedBy = 6 AND &OrderedDsc = True order PesDtaAdm when &OrderedBy = 7 AND &OrderedDsc = False order (PesDtaAdm) when &OrderedBy = 7 AND &OrderedDsc = True order PesDtaDem when &OrderedBy = 8 AND &OrderedDsc = False order (PesDtaDem) when &OrderedBy = 8 AND &OrderedDsc = True
using DSWWFuncionarioSalario(&PesCod, &IncluirDemitidos, &DynamicFiltersSelector1, &DynamicFiltersOperator1, &PesRaz1, &DynamicFiltersEnabled2 , &DynamicFiltersSelector2, &DynamicFiltersOperator2, &PesRaz2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &DynamicFiltersOperator3 , &PesRaz3, &PesIsFun)
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWFuncionarioSalarioGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWFuncionarioSalarioGridState")) Else &GridState.FromXml(&Session.Get(!"WWFuncionarioSalarioGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PESCOD" &PesCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"INCLUIRDEMITIDOS" &IncluirDemitidos.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESISFUN" &PesIsFun.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforePrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterPrintLine'
